import React from 'react';
import { PlusSquare, Upload, Download } from 'lucide-react';

const Toolbar = ({ onAdd, onSmartImport, onExport, isImporting }) => {
  return (
    <div style={{ display: 'flex', gap: '1rem', padding: '1.5rem 2rem 0.5rem', backgroundColor: '#fff' }}>
      
      <button className="btn btn-primary" onClick={onAdd}>
        <PlusSquare size={18} /> Thêm bài tập
      </button>

      {/* Nút Import Đa Năng */}
      <label className="btn" style={{ backgroundColor: '#e0f2fe', color: '#0284c7', cursor: isImporting ? 'not-allowed' : 'pointer', border: '1px solid #bae6fd' }}>
        <input 
          type="file" 
          accept=".tex,.txt,image/png,image/jpeg,application/pdf" 
          multiple 
          style={{ display: 'none' }} 
          onChange={onSmartImport} 
          disabled={isImporting}
        />
        <Upload size={18} /> {isImporting ? 'Đang xử lý đa luồng...' : 'Import File/Ảnh/PDF'}
      </label>

      {/* Nút Xuất đề */}
      <div style={{ marginLeft: 'auto' }}>
        <button className="btn" style={{ backgroundColor: '#f0fdf4', color: '#16a34a', border: '1px solid #bbf7d0' }} onClick={onExport}>
          <Download size={18} /> Xuất Đề Thi
        </button>
      </div>

    </div>
  );
};

export default Toolbar;
